/**
 * Utility to detect if the current browser needs scrollbar overlay fix
 * This includes Safari (WebKit-based but not Chrome) and Firefox
 * @returns boolean indicating if browser needs scrollbar fix
 */
export const needsScrollbarFix = (): boolean => {
  if (typeof navigator === 'undefined') {
    return false;
  }

  const userAgent = navigator.userAgent.toLowerCase();

  // Safari (WebKit-based but not Chrome/Chromium)
  const isSafari =
    /webkit/.test(userAgent) && !/chrome|chromium|crios/.test(userAgent);

  // Firefox
  const isFirefox = /firefox/.test(userAgent);

  return isSafari || isFirefox;
};
